/**
 * MedX submit forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Submit lifecycle, debounce, and double-submit guard.
 */
const SUBMIT_TOKENS = Object.freeze({
  primary: { value: "forms-submit-primary", scope: "forms" },
  secondary: { value: "forms-submit-secondary", scope: "forms" },
  muted: { value: "forms-submit-muted", scope: "forms" },
  accent: { value: "forms-submit-accent", scope: "forms" },
  surface: { value: "forms-submit-surface", scope: "forms" },
});

const SUBMIT_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SUBMIT_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const submitRegistry = new Map();
const SUBMIT_listeners = new Set();
let SUBMIT_seq = 0;

function createSubmitId(prefix = "medx-forms-submit") {
  SUBMIT_seq += 1;
  return `${prefix}-${SUBMIT_seq}`;
}

function registerSubmit(config = {}) {
  const entryId = config.id ?? createSubmitId();
  const preset = SUBMIT_PRESETS[config.preset ?? "default"] ?? SUBMIT_PRESETS.default;
  const token = SUBMIT_TOKENS[config.token ?? preset.token] ?? SUBMIT_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SUBMIT_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  submitRegistry.set(entryId, entry);
  notifySubmitListeners("register", entry);
  return entry;
}

function updateSubmit(id, patch = {}) {
  const entry = submitRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySubmitListeners("update", entry);
  return entry;
}

function resolveSubmit(id) {
  const entry = submitRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSubmitEntries(filter = {}) {
  let items = Array.from(submitRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSubmitEvent(listener) {
  SUBMIT_listeners.add(listener);
  return () => SUBMIT_listeners.delete(listener);
}

function notifySubmitListeners(type, entry) {
  for (const listener of SUBMIT_listeners) {
    try {
      listener({ type, entry, registrySize: submitRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:submit] listener error", err.message);
    }
  }
}

function getSubmitMetrics() {
  const items = listSubmitEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SUBMIT_TOKENS).length,
    presets: Object.keys(SUBMIT_PRESETS).length,
  };
}

async function runMedxSubmit() {
  console.log("[medx:ui:forms:submit] runtime initialized");
  console.log(`[medx:ui:forms:submit] tokens=${Object.keys(SUBMIT_TOKENS).length} presets=${Object.keys(SUBMIT_PRESETS).length}`);

  const events = [];
  onSubmitEvent((e) => events.push(e.type));

  const domains = Object.keys(SUBMIT_SUPPLY_CHAIN);
  const presets = Object.keys(SUBMIT_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSubmit({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/submit" },
    });
  }

  const first = listSubmitEntries()[0];
  if (first) updateSubmit(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSubmitMetrics();
  const resolved = first ? resolveSubmit(first.id) : null;

  console.log(`[medx:ui:forms:submit] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:submit] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:submit] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:submit] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:submit] bootstrap complete");
}

module.exports = runMedxSubmit;
